```typescript
import { HttpStatus } from '../enums/http-status.enum';
import { HttpException, HttpExceptionOptions } from './http.exception';

export class TooManyRequestsException extends HttpException {
  constructor(
    descriptionOrOptions: string | HttpExceptionOptions = 'Too Many Requests',
    options?: HttpExceptionOptions,
  ) {
    const { description, httpExceptionOptions } =
      HttpException.extractDescriptionAndOptionsFrom(descriptionOrOptions, options);

    super(
      HttpException.createBody(description, 'Too Many Requests', HttpStatus.TOO_MANY_REQUESTS),
      HttpStatus.TOO_MANY_REQUESTS,
      httpExceptionOptions,
    );
  }
}
```

